mapper.select:
select spm.id as rowId, cspt.name as projTypeName, midcheck_info as midCheckInfo, begin_date as beginDate, end_date as endDate, midcheck_state as midCheckState, note, file_id as fileId, notify_plan as notifyPlan from srm_project_midcheck_list_info spm left join ct_srm_proj_type cspt on cspt.code=spm.proj_type_code where 1=1
and spm.midcheck_info LIKE CONCAT('%', #{projectMidcheckListInfoDto.midCheckInfo}, '%')
and spm.midcheck_state =#{projectMidcheckListInfoDto.midCheckState}
and spm.begin_date >= #{projectMidcheckListInfoDto.beginDate}
and spm.end_date <= #{projectMidcheckListInfoDto.endDate}
